#!/bin/bash
set -e

TARGET="/usr/local/bin/ogage"
BACKUP="/usr/local/bin/ogage-original"
OGAGE_B64=""

echo "Stopping ogage service..."
sudo systemctl stop ogage.service

echo "Backing up original..."
sudo cp -f "$TARGET" "$BACKUP"

echo "Replacing ogage..."
printf '%s' "$OGAGE_B64" | base64 -d | sudo tee "$TARGET" > /dev/null

echo "Setting permissions..."
sudo chmod +x "$TARGET"

echo "Restarting ogage service..."
sudo systemctl restart ogage.service

echo "New hotkeys have been applied."
sleep 3